            init() {
                setTimeout(() => this._inject(), 2500);
                addNavigateRule('bookmarks', () => {
                    this._panel = null;
                    setTimeout(() => this._inject(), 2500);
                });
            },
            destroy() {
                removeNavigateRule('bookmarks');
                this._panel = null;
                document.querySelectorAll('.ytkit-bookmarks-container').forEach(el => el.remove());
            }
